const express = require('express');
const bodyParser = require('body-parser');
const { exec } = require('child_process');
const { Configuration, OpenAIApi } = require('openai');

const app = express();
app.use(bodyParser.json());

const configuration = new Configuration({
  apiKey: 'YOUR_OPENAI_API_KEY',
});
const openai = new OpenAIApi(configuration);

app.post('/generate-code', async (req, res) => {
  const { description } = req.body;

  try {
    const response = await openai.createCompletion({
      model: 'text-davinci-003',
      prompt: description,
      max_tokens: 150,
    });

    const generatedCode = response.data.choices[0].text.trim();

    exec(generatedCode, (error, stdout, stderr) => {
      if (error) {
        return res.status(500).send(`Error executing code: ${stderr}`);
      }
      res.send(`Code executed successfully: ${stdout}`);
    });
  } catch (error) {
    res.status(500).send('Error generating code');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});

